-- 数字工坊题库唯一存放于 Supabase。腾讯云 API 仅用 service_role 读取与判题，不保存题目内容。
-- 依赖：请先执行 004_content_catalog.sql；本文件可在 SQL Editor 重复执行。

on conflict (id) do update set name=excluded.name,slug=excluded.slug,description=excluded.description,theme=excluded.theme,free_chapter_count=excluded.free_chapter_count,published=excluded.published,version=excluded.version;

on conflict (id) do update set world_id=excluded.world_id,name=excluded.name,sort=excluded.sort,is_free=excluded.is_free,published=excluded.published,version=excluded.version,description=excluded.description,intro=excluded.intro,boss_name=excluded.boss_name,boss_description=excluded.boss_description;

on conflict (id) do update set chapter_id=excluded.chapter_id,name=excluded.name,kind=excluded.kind,sort=excluded.sort,pass_score=excluded.pass_score,reward_xp=excluded.reward_xp,published=excluded.published,version=excluded.version,summary=excluded.summary;

on conflict (id) do update set name=excluded.name,summary=excluded.summary,core_fact=excluded.core_fact,category=excluded.category,published=excluded.published,version=excluded.version;

on conflict (id) do update set knowledge_id=excluded.knowledge_id,level_id=excluded.level_id,question_type=excluded.question_type,stem=excluded.stem,options=excluded.options,correct_answer=excluded.correct_answer,explanation=excluded.explanation,difficulty=excluded.difficulty,published=excluded.published,version=excluded.version;

-- 选择题的选项按题目 ID 和选项文本做确定性乱序；正确选项位置不会形成 A/B/C/D 循环。
with source as (
  select q.id,q.options,q.correct_answer #>> '{}' as old_label,
    (select option->>'text' from jsonb_array_elements(q.options->'options') option where option->>'id'=q.correct_answer #>> '{}') as correct_text
  from public.questions q
  where q.id ~ '^numbers-(sequence|reason)-' or q.id ~ '^numbers-boss-(1[1-9]|20)$'
), ordered as (
  select source.id,source.correct_text,option,
    row_number() over (partition by source.id order by md5(source.id || (option->>'text'))) as position
  from source cross join jsonb_array_elements(source.options->'options') option
), reordered as (
  select id,correct_text,
    jsonb_agg(jsonb_set(option,'{id}',to_jsonb(chr(64+position::int))) order by position) as options
  from ordered group by id,correct_text
)
update public.questions q set
  options=jsonb_set(q.options,'{options}',reordered.options),
  correct_answer=to_jsonb((select chr(64+ordered.position::int) from ordered where ordered.id=reordered.id and ordered.option->>'text'=reordered.correct_text))
from reordered where q.id=reordered.id;

-- 共 80 题：基础计算、资料分析、思维能力、数字推理与综合试炼。
